void fatalError( char *procname, char *format, ... ) {
  va_list ap;

  va_start(ap, format);
  fprintf(stderr, "%s: ", procname);
  vfprintf(stderr, format, ap);
  va_end(ap);

  exit(1);
}

// ==================================================
// Manejo de las pausas
//

#define TAM_PASO 500

static int ahora() {
  int div= TAM_PASO/10;
  return (getTime()+div/2)/div;
}

static void esperar(int paso) {
  int actual= getTime();
  int hasta= actual+paso*TAM_PASO;
  do {
    usleep((hasta-actual)*1000);
    actual= getTime();
  } while (actual<hasta);
}

