#include <unistd.h>
#include <string.h>
#include <stdint.h>
#include <pthread.h>

#include "pss.h"
#include "rwlock.h"

struct rwlock {
    pthread_mutex_t mutex;
    pthread_cond_t readCond;
    pthread_cond_t writeCond;
    Queue *readQueue;   // pending readers (dummy tokens)
    Queue *writeQueue;  // pending writers (thread IDs)
    int activeReaders;
    int activeWriters;
};

RWLock *makeRWLock(void) {
    RWLock *rwl = malloc(sizeof(RWLock));
    pthread_mutex_init(&rwl->mutex, NULL);
    pthread_cond_init(&rwl->readCond, NULL);
    pthread_cond_init(&rwl->writeCond, NULL);
    rwl->readQueue = makeQueue();
    rwl->writeQueue = makeQueue();
    rwl->activeReaders = 0;
    rwl->activeWriters = 0;
    return rwl;
}

void destroyRWLock(RWLock *rwl) {
    pthread_mutex_destroy(&rwl->mutex);
    pthread_cond_destroy(&rwl->readCond);
    pthread_cond_destroy(&rwl->writeCond);
    destroyQueue(rwl->readQueue);
    destroyQueue(rwl->writeQueue);
    free(rwl);
}

void enterRead(RWLock *rwl) {
    pthread_mutex_lock(&rwl->mutex);

    // Must wait if a writer is active or writers are pending
    if (rwl->activeWriters > 0 || !emptyQueue(rwl->writeQueue)) {
        // Enqueue this reader
        put(rwl->readQueue, (void*)1);
        // Wait until no active writer and no pending writers
        while (rwl->activeWriters > 0 || !emptyQueue(rwl->writeQueue)) {
            pthread_cond_wait(rwl->readCond, &rwl->mutex);
        }
        // Remove this reader from the queue (FIFO, we're at the front)
        get(rwl->readQueue);
        // Chain: if more readers pending, signal the next one
        if (!emptyQueue(rwl->readQueue)) {
            pthread_cond_signal(rwl->readCond);
        }
    }

    rwl->activeReaders++;
    pthread_mutex_unlock(&rwl->mutex);
}

void exitRead(RWLock *rwl) {
    pthread_mutex_lock(&rwl->mutex);
    rwl->activeReaders--;
    if (rwl->activeReaders == 0 && !emptyQueue(rwl->writeQueue)) {
        // Signal the oldest waiting writer
        pthread_cond_signal(rwl->writeCond);
    }
    pthread_mutex_unlock(&rwl->mutex);
}

void enterWrite(RWLock *rwl) {
    pthread_mutex_lock(&rwl->mutex);

