#define _XOPEN_SOURCE 500
#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <string.h>
#include <stdint.h>
#include <pthread.h>

#include "pss.h"
#include "rwlock.h"

struct rwlock {
  pthread_mutex_t mutex;
  pthread_cond_t  readCond;
  pthread_cond_t  writeCond;
  Queue          *readQueue;   // pending readers (dummy non-NULL tokens)
  Queue          *writeQueue;  // pending writers (thread IDs for FIFO)
  int             activeReaders;
  int             activeWriters; // 0 or 1
};

RWLock *makeRWLock(void) {
  RWLock *rwl = malloc(sizeof(RWLock));
  pthread_mutex_init(&rwl->mutex, NULL);
  pthread_cond_init(&rwl->readCond, NULL);
  pthread_cond_init(&rwl->writeCond, NULL);
  rwl->readQueue     = makeQueue();
  rwl->writeQueue    = makeQueue();
  rwl->activeReaders = 0;
  rwl->activeWriters = 0;
  return rwl;
}

void destroyRWLock(RWLock *rwl) {
  pthread_mutex_destroy(&rwl->mutex);
  pthread_cond_destroy(&rwl->readCond);
  pthread_cond_destroy(&rwl->writeCond);
  destroyQueue(rwl->readQueue);
  destroyQueue(rwl->writeQueue);
  free(rwl);
}

/*
 * Policy:
 *
 * I.   Writer enters immediately if no readers AND no writer active.
 *      Otherwise the request is pending.
 *
 * II.  Reader enters immediately if no writer active AND no pending
 *      writers.  Otherwise the request is pending.
 *
 * III. When a writer finishes (exitWrite):
 *        - If pending readers exist, accept ALL of them (chain via
 *          pthread_cond_signal).
 *        - Else if pending writers exist, accept the oldest one.
 *
 * IV.  When a reader finishes (exitRead) and no other readers remain:
 *        - If pending writers exist, accept the oldest one.
 *
 * Readers and writers alternate: once a writer is pending, no new
 * readers are admitted until that writer (and any that arrived before
 * it) have had their turn.
 *
 * Waiting writers are kept in a FIFO queue (writeQueue) with their
 * thread ID.  When a writer is woken up it verifies it is at the
 * front of the queue.  If not, it re-signals the condition so that
 * the signal propagates to the correct thread.
 *
 * Waiting readers are kept in a FIFO queue (readQueue) with a dummy
 * token.  When a writer finishes it signals ONE reader; that reader
 * (upon entering) signals the next one, and so on, so that all
 * pending readers are eventually admitted without pthread_cond_broadcast.
 */

void enterRead(RWLock *rwl) {
  pthread_mutex_lock(&rwl->mutex);

  /* Rule II: wait if a writer is active or writers are pending */
  if (rwl->activeWriters > 0 || !emptyQueue(rwl->writeQueue)) {
    put(rwl->readQueue, (void *)1);   /* enqueue this reader */
    while (rwl->activeWriters > 0 || !emptyQueue(rwl->writeQueue)) {
      pthread_cond_wait(rwl->readCond, &rwl->mutex);
    }
    get(rwl->readQueue);              /* remove ourselves from the queue */

    /* Chain: if more readers are waiting, signal the next one */
    if (!emptyQueue(rwl->readQueue)) {
      pthread_cond_signal(rwl->readCond);
    }
  }

  rwl->activeReaders++;
  pthread_mutex_unlock(&rwl->mutex);
}

void exitRead(RWLock *rwl) {
  pthread_mutex_lock(&rwl->mutex);

  rwl->activeReaders--;
  /* Rule IV: when the last reader leaves, admit the oldest writer */
  if (rwl->activeReaders == 0 && !emptyQueue(rwl->writeQueue)) {
    pthread_cond_signal(rwl->writeCond);
  }

  pthread_mutex_unlock(&rwl->mutex);
}

void enterWrite(RWLock *rwl) {
  pthread_mutex_lock(&rwl->mutex);

  /* Rule I (+ FIFO fairness among writers): wait if readers, a
     writer, or pending writers exist */
  if (rwl->activeReaders > 0 || rwl->activeWriters > 0
      || !emptyQueue(rwl->writeQueue)) {
    put(rwl->writeQueue, (void *)pthread_self());  /* enqueue with thread ID */
    while (rwl->activeReaders > 0 || rwl->activeWriters > 0
           || peek(rwl->writeQueue) != (void *)pthread_self()) {
      /* If we are not at the front, re-signal so the correct
         thread eventually gets woken (signal propagation) */
      if (peek(rwl->writeQueue) != (void *)pthread_self()) {
        pthread_cond_signal(rwl->writeCond);
      }
      pthread_cond_wait(rwl->writeCond, &rwl->mutex);
    }
    get(rwl->writeQueue);              /* remove ourselves from the queue */
  }

  rwl->activeWriters = 1;
  pthread_mutex_unlock(&rwl->mutex);
}

void exitWrite(RWLock *rwl) {
  pthread_mutex_lock(&rwl->mutex);

  rwl->activeWriters = 0;

  /* Rule III: admit pending readers (all, via chaining),
     or else the oldest pending writer */
  if (!emptyQueue(rwl->readQueue)) {
    pthread_cond_signal(rwl->readCond);
  } else if (!emptyQueue(rwl->writeQueue)) {
    pthread_cond_signal(rwl->writeCond);
  }

  pthread_mutex_unlock(&rwl->mutex);
}

