#define _XOPEN_SOURCE 500
#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <string.h>
#include <stdint.h>
#include <pthread.h>

#include "pss.h"
#include "rwlock.h"

/*
 * Implementation of a readers-writers lock with alternating entries.
 *
 * Policy (CC4302 Tarea 3):
 *   I.   Writer enters immediately if no readers AND no writer active.
 *        Otherwise the request is pending.
 *   II.  Reader enters immediately if no writer active AND no pending
 *        writers.  Otherwise the request is pending.
 *   III. When a writer finishes (exitWrite):
 *          - If pending readers exist, accept ALL of them.
 *          - Else if pending writers exist, accept the oldest one.
 *   IV.  When a reader finishes (exitRead) and no other readers remain:
 *          - If pending writers exist, accept the oldest one.
 *
 * The implementation uses the "request pattern": each waiting thread
 * creates a small request structure on its stack containing a condition
 * variable and a flag.  The request is placed in a FIFO queue (one for
 * readers, one for writers).  When a writer finishes and decides to
 * admit readers, it dequeues each pending ReadRequest and signals its
 * condition variable individually (avoids pthread_cond_broadcast).
 * Similarly, when a writer or the last reader admits the next writer,
 * it dequeues the oldest WriteRequest and signals it.
 */

/* ── Per-thread request structures ─────────────────────────── */

typedef struct {
  pthread_cond_t cond;
  volatile int   admitted;   /* 1 once the holding thread has been admitted */
} ReadRequest;

typedef struct {
  pthread_cond_t cond;
  volatile int   admitted;
} WriteRequest;

/* ── The lock structure ────────────────────────────────────── */

struct rwlock {
  pthread_mutex_t mutex;
  Queue          *readQueue;    /* FIFO of ReadRequest * (pending readers)  */
  Queue          *writeQueue;   /* FIFO of WriteRequest * (pending writers) */
  int             activeReaders;
  int             activeWriters; /* 0 or 1 */
};

/* ── Public API ────────────────────────────────────────────── */

RWLock *makeRWLock(void) {
  RWLock *rwl = malloc(sizeof(RWLock));
  pthread_mutex_init(&rwl->mutex, NULL);
  rwl->readQueue     = makeQueue();
  rwl->writeQueue    = makeQueue();
  rwl->activeReaders = 0;
  rwl->activeWriters = 0;
  return rwl;
}

void destroyRWLock(RWLock *rwl) {
  pthread_mutex_destroy(&rwl->mutex);
  destroyQueue(rwl->readQueue);
  destroyQueue(rwl->writeQueue);
  free(rwl);
}

void enterRead(RWLock *rwl) {
  ReadRequest req;
  pthread_cond_init(&req.cond, NULL);
  req.admitted = 0;

  pthread_mutex_lock(&rwl->mutex);

  /*
   * Rule II: wait if a writer is active OR writers are pending.
   *
   * Once we have waited and been admitted (req.admitted == 1), we
   * proceed regardless of any remaining writers in the queue (rule III).
   */
  if (rwl->activeWriters > 0 || !emptyQueue(rwl->writeQueue)) {
    put(rwl->readQueue, &req);
    while (!req.admitted) {
      pthread_cond_wait(&req.cond, &rwl->mutex);
    }
    /* The request was dequeued by the signalling writer (or by an
       earlier reader in the chain if we use chaining, but here we
       use direct signalling so the request is already gone). */
  }

  rwl->activeReaders++;
  pthread_mutex_unlock(&rwl->mutex);
  pthread_cond_destroy(&req.cond);
}

void exitRead(RWLock *rwl) {
  pthread_mutex_lock(&rwl->mutex);

  rwl->activeReaders--;

  /* Rule IV: when the last reader leaves, admit the oldest writer. */
  if (rwl->activeReaders == 0 && !emptyQueue(rwl->writeQueue)) {
    WriteRequest *wreq = get(rwl->writeQueue);
    wreq->admitted = 1;
    pthread_cond_signal(&wreq->cond);
  }

  pthread_mutex_unlock(&rwl->mutex);
}

void enterWrite(RWLock *rwl) {
  WriteRequest req;
  pthread_cond_init(&req.cond, NULL);
  req.admitted = 0;

  pthread_mutex_lock(&rwl->mutex);

  /*
   * Rule I + FIFO fairness: wait if readers, a writer, or pending
   * writers exist.
   */
  if (rwl->activeReaders > 0 || rwl->activeWriters > 0
      || !emptyQueue(rwl->writeQueue)) {
    put(rwl->writeQueue, &req);
    while (!req.admitted) {
      pthread_cond_wait(&req.cond, &rwl->mutex);
    }
    /* The request was dequeued by the signalling exitWrite or exitRead. */
  }

  rwl->activeWriters = 1;
  pthread_mutex_unlock(&rwl->mutex);
  pthread_cond_destroy(&req.cond);
}

void exitWrite(RWLock *rwl) {
  pthread_mutex_lock(&rwl->mutex);

  rwl->activeWriters = 0;

  /*
   * Rule III: admit ALL pending readers, or else the oldest writer.
   *
   * We dequeue each pending ReadRequest and signal its condition
   * individually (no broadcast).  The queuing discipline of the
   * condition-variable scheduler is irrelevant because each reader
   * waits on its own private condition.
   */
  if (!emptyQueue(rwl->readQueue)) {
    while (!emptyQueue(rwl->readQueue)) {
      ReadRequest *rreq = get(rwl->readQueue);
      rreq->admitted = 1;
      pthread_cond_signal(&rreq->cond);
    }
  } else if (!emptyQueue(rwl->writeQueue)) {
    WriteRequest *wreq = get(rwl->writeQueue);
    wreq->admitted = 1;
    pthread_cond_signal(&wreq->cond);
  }

  pthread_mutex_unlock(&rwl->mutex);
}

