#define _XOPEN_SOURCE 500
#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <string.h>
#include <stdint.h>
#include <pthread.h>

#include "pss.h"
#include "rwlock.h"

/*
 * Implementation of a readers-writers lock with alternating entries.
 *
 * Policy (CC4302 Tarea 3):
 *   I.   Writer enters immediately if no readers AND no writer active.
 *        Otherwise the request is pending.
 *   II.  Reader enters immediately if no writer active AND no pending
 *        writers.  Otherwise the request is pending.
 *   III. When a writer finishes (exitWrite):
 *          - If pending readers exist, accept ALL of them.
 *          - Else if pending writers exist, accept the oldest one.
 *   IV.  When a reader finishes (exitRead) and no other readers remain:
 *          - If pending writers exist, accept the oldest one.
 *
 * The implementation uses the "request pattern": each waiting thread
 * creates a small request structure on its stack containing a condition
 * variable and an "admitted" flag.  The request is placed in a FIFO
 * queue (one for readers, one for writers).
 *
 * When a writer finishes and decides to admit readers, it dequeues
 * each pending ReadRequest from readQueue, sets its "admitted" flag,
 * signals its condition, and increments a readersInFlight counter.
 * This counter prevents a new writer from sneaking in after the
 * readers have been dequeued/signalled but before they have actually
 * entered (incremented activeReaders).
 *
 * When a reader or writer is woken, it checks its own "admitted" flag
 * (spurious-wakeup safe) and then proceeds to modify the shared state.
 */

/* ── Per-thread request structures ─────────────────────────── */

typedef struct {
  pthread_cond_t cond;
  volatile int   admitted;   /* 1 once the holding thread has been admitted */
} ReadRequest;

typedef struct {
  pthread_cond_t cond;
  volatile int   admitted;
} WriteRequest;

/* ── The lock structure ────────────────────────────────────── */

struct rwlock {
  pthread_mutex_t mutex;
  Queue          *readQueue;     /* FIFO of ReadRequest *  */
  Queue          *writeQueue;    /* FIFO of WriteRequest * */
  int             activeReaders;
  int             activeWriters;  /* 0 or 1 */
  int             readersInFlight; /* #readers dequeued from readQueue but
                                     not yet inside (activeReaders++) */
};

/* ── Public API ────────────────────────────────────────────── */

RWLock *makeRWLock(void) {
  RWLock *rwl = malloc(sizeof(RWLock));
  pthread_mutex_init(&rwl->mutex, NULL);
  rwl->readQueue      = makeQueue();
  rwl->writeQueue     = makeQueue();
  rwl->activeReaders  = 0;
  rwl->activeWriters  = 0;
  rwl->readersInFlight = 0;
  return rwl;
}

void destroyRWLock(RWLock *rwl) {
  pthread_mutex_destroy(&rwl->mutex);
  destroyQueue(rwl->readQueue);
  destroyQueue(rwl->writeQueue);
  free(rwl);
}

void enterRead(RWLock *rwl) {
  ReadRequest req;
  pthread_cond_init(&req.cond, NULL);
  req.admitted = 0;

  pthread_mutex_lock(&rwl->mutex);

  /*
   * Rule II: wait if a writer is active OR writers are pending.
   *
   * Also wait if readers are already in flight (they were dequeued by
   * exitWrite but haven't finished incrementing activeReaders yet).
   */
  if (rwl->activeWriters > 0
      || !emptyQueue(rwl->writeQueue)
      || rwl->readersInFlight > 0) {
    put(rwl->readQueue, &req);
    while (!req.admitted) {
      pthread_cond_wait(&req.cond, &rwl->mutex);
    }
    /* Dequeued and admitted by exitWrite.  Account our entry. */
    rwl->readersInFlight--;
  }

  rwl->activeReaders++;
  pthread_mutex_unlock(&rwl->mutex);
  pthread_cond_destroy(&req.cond);
}

void exitRead(RWLock *rwl) {
  pthread_mutex_lock(&rwl->mutex);

  rwl->activeReaders--;

  /*
   * Rule IV: when the last reader leaves, and no readers are still
   * "in flight", admit the oldest pending writer (if any).
   */
  if (rwl->activeReaders == 0
      && rwl->readersInFlight == 0
      && !emptyQueue(rwl->writeQueue)) {
    WriteRequest *wreq = get(rwl->writeQueue);
    wreq->admitted = 1;
    pthread_cond_signal(&wreq->cond);
  }

  pthread_mutex_unlock(&rwl->mutex);
}

void enterWrite(RWLock *rwl) {
  WriteRequest req;
  pthread_cond_init(&req.cond, NULL);
  req.admitted = 0;

  pthread_mutex_lock(&rwl->mutex);

  /*
   * Rule I + FIFO fairness: wait if readers, a writer, pending
   * writers, OR readers-in-flight exist (the latter prevents a new
   * writer from overtaking readers that were just admitted by a
   * previous exitWrite but haven't entered yet).
   */
  if (rwl->activeReaders > 0
      || rwl->activeWriters > 0
      || !emptyQueue(rwl->writeQueue)
      || rwl->readersInFlight > 0) {
    put(rwl->writeQueue, &req);
    while (!req.admitted) {
      pthread_cond_wait(&req.cond, &rwl->mutex);
    }
  }

  rwl->activeWriters = 1;
  pthread_mutex_unlock(&rwl->mutex);
  pthread_cond_destroy(&req.cond);
}

void exitWrite(RWLock *rwl) {
  pthread_mutex_lock(&rwl->mutex);

  rwl->activeWriters = 0;

  /*
   * Rule III: admit ALL pending readers, or else the oldest writer.
   *
   * For readers: we dequeue each ReadRequest, set its admitted flag,
   * and signal its private condition.  readersInFlight is incremented
   * so that new writers (or new readers) don't cut in line before all
   * these readers have actually entered.
   */
  if (!emptyQueue(rwl->readQueue)) {
    int n = 0;
    while (!emptyQueue(rwl->readQueue)) {
      ReadRequest *rreq = get(rwl->readQueue);
      rreq->admitted = 1;
      pthread_cond_signal(&rreq->cond);
      n++;
    }
    rwl->readersInFlight += n;
  } else if (!emptyQueue(rwl->writeQueue)) {
    WriteRequest *wreq = get(rwl->writeQueue);
    wreq->admitted = 1;
    pthread_cond_signal(&wreq->cond);
  }

  pthread_mutex_unlock(&rwl->mutex);
}

