#define _XOPEN_SOURCE 500
#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <string.h>
#include <stdint.h>
#include <pthread.h>

#include "pss.h"
#include "rwlock.h"

/*
 * Implementation of a readers-writers lock with alternating entries.
 *
 * Policy (CC4302 Tarea 3):
 *   I.   Writer enters immediately if no readers AND no writer active.
 *        Otherwise the request is pending.
 *   II.  Reader enters immediately if no writer active AND no pending
 *        writers.  Otherwise the request is pending.
 *   III. When a writer finishes (exitWrite):
 *          - If pending readers exist, accept ALL of them.
 *          - Else if pending writers exist, accept the oldest one.
 *   IV.  When a reader finishes (exitRead) and no other readers remain:
 *          - If pending writers exist, accept the oldest one.
 *
 * The implementation uses the "request pattern": each waiting thread
 * creates a small request structure on its stack containing a condition
 * variable and an "admitted" flag.  The request is placed in a FIFO
 * queue (one for readers, one for writers).
 *
 * When a writer finishes and decides to admit readers, it dequeues
 * each pending ReadRequest from readQueue, sets its "admitted" flag,
 * signals its condition, and increments a readersInFlight counter.
 * This counter prevents a new writer from sneaking in after the
 * readers have been dequeued/signalled but before they have actually
 * entered (incremented activeReaders).
 *
 * When a reader or writer is woken, it checks its own "admitted" flag
 * (spurious-wakeup safe) and then proceeds to modify the shared state.
 */

/* ── Per-thread request structures ─────────────────────────── */

typedef struct {
  pthread_cond_t cond;
  volatile int   admitted;   /* 1 once the holding thread has been admitted */
} ReadRequest;

typedef struct {
  pthread_cond_t cond;
  volatile int   admitted;
} WriteRequest;

/* ── The lock structure ────────────────────────────────────── */

struct rwlock {
  pthread_mutex_t mutex;
  Queue          *readQueue;     /* FIFO of ReadRequest *  */
  Queue          *writeQueue;    /* FIFO of WriteRequest * */
  int             activeReaders;
  int             activeWriters;  /* 0 or 1 */
  int             readersInFlight; /* #readers dequeued from readQueue but
                                     not yet inside (activeReaders++) */
  int             writersInFlight; /* #writers dequeued from writeQueue but
                                     not yet inside (activeWriters=1)  */
};

/* ── Public API ────────────────────────────────────────────── */

RWLock *makeRWLock(void) {
  RWLock *rwl = malloc(sizeof(RWLock));
  pthread_mutex_init(&rwl->mutex, NULL);
  rwl->readQueue      = makeQueue();
  rwl->writeQueue     = makeQueue();
  rwl->activeReaders  = 0;
  rwl->activeWriters  = 0;
  rwl->readersInFlight = 0;
  rwl->writersInFlight = 0;
  return rwl;
}

void destroyRWLock(RWLock *rwl) {
  pthread_mutex_destroy(&rwl->mutex);
  destroyQueue(rwl->readQueue);
  destroyQueue(rwl->writeQueue);
  free(rwl);
}

